#include <stdio.h>
#include <stdlib.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N;
        scanf("%lld", &N);
        long long d = llabs(N) % 10LL;
        if (d == 0LL || d == 5LL) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

